#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-19
#
# MDX compile guard — exercises scripts/test-mdx-compile.mjs both ways:
# 1. Asserts every docs/site/content/docs/**/*.mdx compiles cleanly.
# 2. Asserts the counter-example fixture (tests/fixtures/nested-fence.mdx)
#    is REJECTED by the same checker.
#
# This dual-direction TDD safety net ensures the guard stays sharp:
# if step 1 starts passing on a broken file, OR step 2 starts succeeding
# on the deliberately-broken fixture, this test fails.
#
# Origin: PR #1401 — protects against the class of bug fixed in #1399
# (nested same-length code fences in skill SKILL.md sources).

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
DOCS_SITE="$PROJECT_ROOT/docs/site"
SCRIPT="$DOCS_SITE/scripts/test-mdx-compile.mjs"
FIXTURE="$DOCS_SITE/tests/fixtures/nested-fence.mdx"

RED=$'\033[0;31m'
GREEN=$'\033[0;32m'
YELLOW=$'\033[1;33m'
NC=$'\033[0m'

PASS=0
FAIL=0

pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

echo "════════════════════════════════════════════════════════════════"
echo "  MDX Compile Guard"
echo "════════════════════════════════════════════════════════════════"
echo ""

# Pre-flight: ensure the script and fixture exist
if [[ ! -f "$SCRIPT" ]]; then
  echo "  ${RED}✗${NC} Missing: $SCRIPT"
  exit 1
fi
if [[ ! -f "$FIXTURE" ]]; then
  echo "  ${RED}✗${NC} Missing: $FIXTURE"
  exit 1
fi

# Pre-flight: ensure docs/site has node_modules (the script needs @mdx-js/mdx
# from there — provided directly via devDeps, with fumadocs-mdx as a backstop)
if [[ ! -d "$DOCS_SITE/node_modules/@mdx-js/mdx" ]]; then
  echo "  ${YELLOW}⚠${NC} @mdx-js/mdx not in docs/site/node_modules — running npm install there"
  (cd "$DOCS_SITE" && npm install --no-audit --no-fund 2>&1 | tail -3) || {
    fail "npm install failed in docs/site"
    exit 1
  }
fi

# ─── Test 1: every published mdx must compile ───────────────────────
echo "▶ Test 1: docs/site/content/docs/**/*.mdx all compile cleanly"
echo "────────────────────────────────────────────────────────────────"
if (cd "$DOCS_SITE" && node "$SCRIPT" 2>&1); then
  pass "All published mdx files compile"
else
  fail "At least one published mdx file failed to compile"
fi
echo ""

# ─── Test 2: counter-example MUST fail ──────────────────────────────
echo "▶ Test 2: counter-example fixture is rejected"
echo "────────────────────────────────────────────────────────────────"
if (cd "$DOCS_SITE" && node "$SCRIPT" "$FIXTURE" >/dev/null 2>&1); then
  fail "Counter-example $(basename "$FIXTURE") was NOT rejected — guard is broken"
  echo "    The fixture is supposed to fail. If it now compiles, either"
  echo "    @mdx-js/mdx changed its parser behavior, or someone 'fixed' the fixture."
  echo "    Investigate before proceeding — do not silently update the fixture."
else
  pass "Counter-example correctly rejected by the guard"
fi
echo ""

# ─── Summary ─────────────────────────────────────────────────────────
echo "════════════════════════════════════════════════════════════════"
echo "  Total: $((PASS + FAIL))  |  Passed: ${GREEN}${PASS}${NC}  |  Failed: ${RED}${FAIL}${NC}"
echo "════════════════════════════════════════════════════════════════"

[[ $FAIL -eq 0 ]] || exit 1
exit 0
